using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace McpServer;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _httpClient;

    // Constructor injection — the DI container provides the HttpClient automatically
    public WeatherTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [McpServerTool, Description("Get current weather forecast for a US location by latitude/longitude.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var pointUrl = $"https://api.weather.gov/points/{latitude},{longitude}";
        var point = await _httpClient.GetFromJsonAsync<PointResponse>(pointUrl, cancellationToken);

        if (point?.Properties?.Forecast is null)
            return "Unable to resolve forecast URL for this location.";

        var forecast = await _httpClient.GetFromJsonAsync<ForecastResponse>(
            point.Properties.Forecast, cancellationToken);

        if (forecast?.Properties?.Periods is not { Count: > 0 })
            return "No forecast data available.";

        var period = forecast.Properties.Periods[0];
        return $"{period.Name}: {period.Temperature}°{period.TemperatureUnit} — {period.DetailedForecast}";
    }

    [McpServerTool, Description("List active weather alerts for a US state (two-letter code, e.g. 'CA').")]
    public async Task<string> GetAlerts(
        [Description("Two-letter US state code")] string state,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.weather.gov/alerts/active?area={state}";
        var response = await _httpClient.GetFromJsonAsync<AlertResponse>(url, cancellationToken);

        if (response?.Features is not { Count: > 0 })
            return "No active alerts for this state.";

        var summaries = response.Features
            .Take(5)
            .Select(f => $"• {f.Properties.Event}: {f.Properties.Headline}");

        return string.Join("\n", summaries);
    }
}

// --- JSON response models ---

public record PointResponse(
    [property: JsonPropertyName("properties")] PointProperties? Properties);

public record PointProperties(
    [property: JsonPropertyName("forecast")] string? Forecast);

public record ForecastResponse(
    [property: JsonPropertyName("properties")] ForecastProperties? Properties);

public record ForecastProperties(
    [property: JsonPropertyName("periods")] List<ForecastPeriod>? Periods);

public record ForecastPeriod(
    [property: JsonPropertyName("name")] string Name,
    [property: JsonPropertyName("temperature")] int Temperature,
    [property: JsonPropertyName("temperatureUnit")] string TemperatureUnit,
    [property: JsonPropertyName("detailedForecast")] string DetailedForecast);

public record AlertResponse(
    [property: JsonPropertyName("features")] List<AlertFeature>? Features);

public record AlertFeature(
    [property: JsonPropertyName("properties")] AlertProperties Properties);

public record AlertProperties(
    [property: JsonPropertyName("event")] string Event,
    [property: JsonPropertyName("headline")] string Headline);

