using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

var builder = Host.CreateApplicationBuilder(args);

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

// Register a named HttpClient that the DI container injects into tool classes
builder.Services.AddHttpClient<McpServer.WeatherTools>(client =>
{
    client.BaseAddress = new Uri("https://api.weather.gov");
    client.DefaultRequestHeaders.UserAgent.ParseAdd("McpWeatherServer/1.0");
});

var app = builder.Build();
await app.RunAsync();

